// Get start date and context from previous node
const startDate = new Date($input.first().json.campaign_start_date);
const context = $input.first().json.campaign_context;
const today = new Date();

// Calculate difference in time
const diffTime = Math.abs(today - startDate);
const diffDays = Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 

// Calculate Week Number (0-11)
const currentWeek = Math.floor(diffDays / 7);

// Determine Day of Week
const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday'];
const currentDay = days[today.getDay()];

// Select the specific instruction based on the day
let dayInstruction = "";

if (currentDay === 'Monday') {
    dayInstruction = "Today is MONDAY. Focus on the ROLE REVEAL. Refer to the 'Role' and 'Content' for the current week in the schedule.";
} else if (currentDay === 'Wednesday') {
    dayInstruction = "Today is WEDNESDAY. Focus on the TECH FLEX. Refer to the 'Tech Flex' achievement for the current week.";
} else if (currentDay === 'Friday') {
    dayInstruction = "Today is FRIDAY. Focus on the SUCCESS STORY/Transformation. Refer to the specific Role and Flex to write a before/after story.";
} else {
    dayInstruction = "Today is a generic engagement day. Share a tip related to software engineering or the current week's role.";
}

return {
    current_week: currentWeek,
    current_day: currentDay,
    day_instruction: dayInstruction,
    campaign_context: context,
    // Pass through other fields
    AppName: $input.first().json.AppName
};

